package com.example.authserver.config;

import java.util.Collections;
import java.util.HashSet;
import java.util.Set;

import jakarta.servlet.http.HttpServletRequest;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.oauth2.core.AuthorizationGrantType;
import org.springframework.security.oauth2.server.authorization.authentication.OAuth2ClientCredentialsAuthenticationToken;
import org.springframework.security.oauth2.server.authorization.web.authentication.OAuth2ClientCredentialsAuthenticationConverter;
import org.springframework.security.web.authentication.AuthenticationConverter;
import org.springframework.util.StringUtils;

@Configuration
public class ClientCredentialsScopePassthroughConfig {

    @Bean
    AuthenticationConverter clientCredentialsAuthenticationConverter() {
        return new PassthroughScopesClientCredentialsAuthenticationConverter();
    }

    static final class PassthroughScopesClientCredentialsAuthenticationConverter extends OAuth2ClientCredentialsAuthenticationConverter {
        @Override
        public OAuth2ClientCredentialsAuthenticationToken convert(HttpServletRequest request) {
            OAuth2ClientCredentialsAuthenticationToken token = super.convert(request);
            if (token == null) return null;

            String scopeParam = request.getParameter("scope");
            Set<String> requestedScopes = parseScopes(scopeParam);

            return new OAuth2ClientCredentialsAuthenticationToken(
                    token.getClientPrincipal(),
                    token.getClientAuthenticationMethod(),
                    token.getAdditionalParameters(),
                    requestedScopes
            );
        }

        private static Set<String> parseScopes(String scope) {
            if (!StringUtils.hasText(scope)) return Collections.emptySet();
            String[] parts = StringUtils.tokenizeToStringArray(scope, " ");
            Set<String> set = new HashSet<>();
            if (parts != null) {
                Collections.addAll(set, parts);
            }
            return set;
        }
    }
}

package com.example.authserver.config;

import org.springframework.beans.factory.ObjectProvider;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.oauth2.server.authorization.authentication.OAuth2ClientCredentialsAuthenticationProvider;
import org.springframework.security.oauth2.server.authorization.client.RegisteredClientRepository;
import org.springframework.security.oauth2.server.authorization.settings.AuthorizationServerSettings;
import org.springframework.security.oauth2.server.authorization.token.OAuth2TokenGenerator;
import org.springframework.security.oauth2.server.authorization.web.authentication.OAuth2TokenEndpointFilter;
import org.springframework.security.web.authentication.AuthenticationConverter;
import org.springframework.security.web.authentication.AuthenticationFailureHandler;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.security.web.util.matcher.AntPathRequestMatcher;

@Configuration
public class TokenEndpointConfig {

    @Bean
    OAuth2TokenEndpointFilter tokenEndpointFilter(
            HttpSecurity http,
            AuthenticationManager authenticationManager,
            ObjectProvider<AuthenticationSuccessHandler> successHandler,
            ObjectProvider<AuthenticationFailureHandler> failureHandler,
            ObjectProvider<AuthenticationConverter> clientCredentialsAuthenticationConverter
    ) {
        OAuth2TokenEndpointFilter filter = new OAuth2TokenEndpointFilter(authenticationManager, "/oauth2/token");
        AuthenticationConverter converter = clientCredentialsAuthenticationConverter.getIfAvailable();
        if (converter != null) {
            filter.setAuthenticationConverter(converter);
        }
        AuthenticationSuccessHandler sh = successHandler.getIfAvailable();
        if (sh != null) filter.setAuthenticationSuccessHandler(sh);
        AuthenticationFailureHandler fh = failureHandler.getIfAvailable();
        if (fh != null) filter.setAuthenticationFailureHandler(fh);
        return filter;
    }
}

